shop.query:
#graphql
  query ShopOwnerMetafieldsShopId {
    shop {
      id
      name
      myshopifyDomain
    }
  }

set.query:
mutation ShopOwnerMetafieldsSet($metafields: [MetafieldsSetInput!]!) {
  metafieldsSet(metafields: $metafields) {
    metafields {
      namespace
      key
      type
      value
      ownerType
      owner {
        __typename
        ... on Shop {
          id
        }
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

readAfterSet.query:
query ShopOwnerMetafieldsRead($namespace: String!, $key: String!) {
  shop {
    id
    single: metafield(namespace: $namespace, key: $key) {
      namespace
      key
      type
      value
      ownerType
      owner {
        __typename
        ... on Shop {
          id
        }
      }
    }
    list: metafields(first: 10, namespace: $namespace) {
      nodes {
        namespace
        key
        type
        value
        ownerType
      }
    }
  }
}

delete.query:
mutation ShopOwnerMetafieldsDelete($metafields: [MetafieldIdentifierInput!]!) {
  metafieldsDelete(metafields: $metafields) {
    deletedMetafields {
      ownerId
      namespace
      key
    }
    userErrors {
      field
      message
    }
  }
}

